-- create "shipments" table
CREATE TABLE "shipments" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "carrier" character varying(100) NOT NULL, "tracking_number" character varying(191) NULL, "status" smallint NOT NULL, "shipped_at" timestamptz NULL, "delivered_at" timestamptz NULL, "shop_id" bigint NOT NULL, "order_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "shipments_orders_order" FOREIGN KEY ("order_id") REFERENCES "orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "shipments_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "shipments_status_check" CHECK (status = ANY (ARRAY[1, 2, 3])));
-- create index "shipment_order_id" to table: "shipments"
CREATE UNIQUE INDEX "shipment_order_id" ON "shipments" ("order_id");
-- create index "shipment_shop_id_order_id" to table: "shipments"
CREATE INDEX "shipment_shop_id_order_id" ON "shipments" ("shop_id", "order_id");
-- create "shipping_methods" table
CREATE TABLE "shipping_methods" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "name" character varying(100) NOT NULL, "carrier" character varying(100) NOT NULL, "flat_rate" bigint NOT NULL, "is_active" boolean NOT NULL DEFAULT true, "shop_id" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "shipping_methods_shops_shop" FOREIGN KEY ("shop_id") REFERENCES "shops" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "shipping_methods_flat_rate_check" CHECK (flat_rate >= 0));
-- create index "shippingmethod_shop_id_is_active" to table: "shipping_methods"
CREATE INDEX "shippingmethod_shop_id_is_active" ON "shipping_methods" ("shop_id", "is_active");
